import torch
import triton
import triton.language as tl

def least_squares_qr(A, b, *, mode='reduced', out=None) -> torch.Tensor:
    if A.shape[-2] < A.shape[-1]:
        raise ValueError("Matrix A must have more rows than columns for least squares")

    # Ensure A and b are 3D for batch processing
    batch_dims = A.shape[:-2]
    m, n = A.shape[-2], A.shape[-1]
    k = b.shape[-1] if b.ndim > 1 else 1

    # Reshape to 3D for processing
    A_flat = A.view(-1, m, n)
    b_flat = b.view(-1, m, k)

    # Allocate output tensor
    if out is None:
        out = torch.empty(*batch_dims, n, k, dtype=A.dtype, device=A.device)
    else:
        out = out.view(-1, n, k)

    # Launch kernel
    grid = (A_flat.shape[0], 1, 1)
    _qr_least_squares_kernel[grid](A_flat, b_flat, out, m, n, k, mode)

    return out.view(*batch_dims, n, k)

@triton.jit
def _qr_least_squares_kernel(A, b, x, m, n, k, mode):
    # Get batch index
    batch_idx = tl.program_id(0)

    # Shared memory for QR decomposition
    Q_shared = tl.shared_memory(shape=(m, n), dtype=tl.float32)
    R_shared = tl.shared_memory(shape=(n, n), dtype=tl.float32)

    # Load A and b into shared memory
    for i in range(m):
        for j in range(n):
            if i < m and j < n:
                Q_shared[i, j] = tl.load(A + batch_idx * m * n + i * n + j)

    for i in range(k):
        for j in range(m):
            if j < m:
                tl.store(b + batch_idx * m * k + j * k + i, tl.load(b + batch_idx * m * k + j * k + i))

    # Perform QR decomposition
    _qr_decomposition(Q_shared, R_shared, m, n, mode)

    # Solve Rx = Q^T * b
    _back_substitution(Q_shared, R_shared, b, x, m, n, k)

@triton.jit
def _qr_decomposition(Q, R, m, n, mode):
    # Simple Householder QR decomposition
    for j in range(n):
        # Compute Householder vector
        norm = 0.0
        for i in range(j, m):
            norm += Q[i, j] * Q[i, j]
        norm = tl.sqrt(norm)

        if norm > 0:
            # Compute v = x - sign(x_1) * ||x|| * e_1
            v = Q[j, j] + tl.sign(Q[j, j]) * norm

            # Apply Householder reflection
            for i in range(j, m):
                Q[i, j] = Q[i, j] / v

            # Update R
            for i in range(j, n):
                dot = 0.0
                for l in range(j, m):
                    dot += Q[l, j] * Q[l, i]
                for l in range(j, m):
                    Q[l, i] = Q[l, i] - 2.0 * dot * Q[l, j]

            # Store R
            if j < n:
                R[j, j] = tl.sign(Q[j, j]) * norm
                for i in range(j + 1, n):
                    R[j, i] = Q[j, i]

        # Zero out below diagonal
        for i in range(j + 1, m):
            Q[i, j] = 0.0

@triton.jit
def _back_substitution(Q, R, b, x, m, n, k):
    # Solve Rx = Q^T * b
    for i in range(k):
        for j in range(n - 1, -1, -1):
            sum_val = 0.0
            for l in range(j + 1, n):
                sum_val += R[j, l] * tl.load(x + j * k + i)

            # Compute x[j]
            x_val = (tl.load(b + j * k + i) - sum_val) / R[j, j]
            tl.store(x + j * k + i, x_val)
